def patch_rmsnorm_modules(model, custom_rmsnorm_fn):
    """Patch all RMSNorm modules in a diffusers model."""
    for name, module in model.named_modules():
        if type(module).__name__ == 'RMSNorm':
            eps = getattr(module, 'eps', 1e-6)
            has_weight = hasattr(module, 'weight') and module.weight is not None
            original_forward = module.forward
            def make_forward(mod, _eps, _has_weight):
                def forward(x):
                    weight = mod.weight if _has_weight else None
                    return custom_rmsnorm_fn(x, weight, _eps)
                return forward
            module.forward = make_forward(module, eps, has_weight)
